# PowerShell script to commit Math75-Q2-Addendum-A-RGE-completion
# Generated by CLAUDE (TECT Turn 6 Track B, 2026-04-24)
# Usage: from repo root: .\Codes\scripts\commit_Math75_Q2_RGE_completion.ps1

$ErrorActionPreference = "Stop"

# Verify we're in the repo root
if (-not (Test-Path ".git")) {
    Write-Error "Not in a git repository root. Run from C:\Dev\TECT2\Contents"
    exit 1
}

Write-Host "[Commit] Math75-Q2-Addendum-A-RGE-completion (Turn 6 Track B)" -ForegroundColor Green

# Stage files
$files = @(
    "Docs/math/TECT-Math75-Q2-Addendum-A-RGE-completion.tex.txt",
    "Codes/supplementary/Math75_Q2_RG_integration.py",
    "Docs/manual/CODE_MANUAL.md",
    "CHANGELOG.md"
)

foreach ($file in $files) {
    Write-Host "  Adding: $file"
    git add $file
    if ($LASTEXITCODE -ne 0) {
        Write-Error "Failed to add $file"
        exit 2
    }
}

# Commit with signature
$commitMsg = @"
Math75-Q2-Addendum-A-RGE-completion: Full β-function + solver (Pillar 4 Q2)

[Theory] Math75-Q2-Addendum-A-RGE-completion.tex.txt (v1.0, 380 lines)
