"@

Write-Host "  Committing with signature (jtkor@outlook.com)..."
git -c user.email="jtkor@outlook.com" -c user.name="Jusang Lee" commit -m $commitMsg

if ($LASTEXITCODE -ne 0) {
    Write-Error "Commit failed"
    exit 3
}

Write-Host "✓ Commit successful!" -ForegroundColor Green
git log -1 --oneline
